
export type AcademyItemType = 'model' | 'udl' | 'bloom' | 'tech' | 'tone' | 'focus' | 'assessment' | 'dok' | 'visual';
export type TpackDomain = 'technology' | 'pedagogy' | 'content';

export interface DokClassifyItem {
  question: string;
  correctDok: 1 | 2 | 3 | 4;
  explanation: string;
}

export interface AcademyLesson {
  id: string;
  type: AcademyItemType;
  tpackDomain: TpackDomain;
  title: string;
  theory: string[];
  cognitiveBenefit: string;
  mathExample: string;
  generatorKey: string;
  /** Embed an interactive math tool inside this lesson */
  interactiveDemo?: 'algebra-tiles' | 'shape-3d';
  /** Initial expression shown in the AlgebraTiles manipulative (e.g. 'x²+3x+2') */
  algebraTilesPreset?: string;
  /** DoK classification exercise — teacher picks the DoK level for each item */
  dokClassifyItems?: DokClassifyItem[];
}

